/**
 * @fileoverview ContextMenu component definition for JIT pipeline.
 *
 * @module module/ContextMenu.def
 */

import { PART } from './ContextMenu/constants.js';

/**
 * Definition object for the ContextMenu component.
 * Contains metadata, tokens, states, template slots, and observed attributes.
 * @type {object}
 */
export const ContextMenuDef = {
    name: 'ContextMenu',
    tag: 'rui-context-menu',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    tokens: {
        prefix: 'cm',
        tokens: {
            'min-width':        { value: '180px',           description: 'Menu min width' },
            'max-width':        { value: '320px',           description: 'Menu max width' },
            'radius':           { ref: 'radius.md',         description: 'Menu border radius' },
            'padding-x':        { value: '0',               description: 'Menu horizontal padding' },
            'padding-y':        { value: '4px',             description: 'Menu vertical padding' },
            'font-size':        { value: '0.82rem',         description: 'Menu font size' },
            'item-gap':         { ref: 'spacing.2',         description: 'Item content gap' },
            'item-padding-x':   { value: '0.75rem',         description: 'Item horizontal padding' },
            'item-padding-y':   { value: '0.4rem',          description: 'Item vertical padding' },
            'shortcut-font-size': { value: '0.72rem',       description: 'Shortcut hint font size' },
            'divider-margin-x': { ref: 'spacing.2',         description: 'Divider horizontal margin' },
            'divider-margin-y': { value: '4px',             description: 'Divider vertical margin' },
            'font-stack':       { ref: 'font.family',       description: 'Font family' },
            'bg':               { ref: 'color.bg',          description: 'Menu background' },
            'border':           { ref: 'color.border',      description: 'Menu border color' },
            'shadow':           { ref: 'shadow.lg',         description: 'Menu shadow' },
            'text':             { ref: 'color.text',        description: 'Text color' },
            'text-muted':       { ref: 'color.text-muted',  description: 'Shortcut/arrow color' },
            'bg-hover':         { ref: 'color.bg-hover',    description: 'Item hover background' },
            'z-index':          { ref: 'z-index.contextmenu', description: 'Overlay z-index' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine (menu visibility)
    // ═══════════════════════════════════════
    states: {
        initial: 'closed',
        states: {
            closed: {
                on: { OPEN: 'open' },
            },
            open: {
                on: { CLOSE: 'closed' },
            },
        },
        effects: {},
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    template: {
        slots: {
            menu:     { element: 'div',  classes: ['ctxmenu'],         role: 'menu' },
            item:     { element: 'div',  classes: ['ctxmenu-item'],    role: 'menuitem' },
            divider:  { element: 'div',  classes: ['ctxmenu-divider'], role: 'separator' },
            icon:     { element: 'span', classes: ['ctxmenu-icon'] },
            label:    { element: 'span', classes: ['ctxmenu-label'] },
            shortcut: { element: 'span', classes: ['ctxmenu-shortcut'] },
            arrow:    { element: 'span', classes: ['ctxmenu-arrow'] },
        },
    },

    // ═══════════════════════════════════════
    //  JIT Parts
    // ═══════════════════════════════════════
    jitParts: {
        [PART.MENU]: PART.MENU,
        [PART.ITEM]: PART.ITEM,
        [PART.ICON]: PART.ICON,
        [PART.LABEL]: PART.LABEL,
        [PART.SHORTCUT]: PART.SHORTCUT,
        [PART.ARROW]: PART.ARROW,
        [PART.DIVIDER]: PART.DIVIDER,
        [PART.RICH]: PART.RICH,
    },

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    observedAttrs: ['trigger'],
    attrMap: {
        trigger: 'trigger',
    },
};

export default ContextMenuDef;
