/**
 * @fileoverview ContextMenu constants - CSS classes, ARIA attrs, selectors, defaults.
 * @module module/ContextMenu/constants
 */

import Icons from '../Icons.js';
import { TRUNCATE } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    MENU:       'ctxmenu',
    DIVIDER:    'ctxmenu-divider',
    ITEM:       'ctxmenu-item',
    ICON:       'ctxmenu-icon',
    LABEL:      'ctxmenu-label',
    SHORTCUT:   'ctxmenu-shortcut',
    ARROW:      'ctxmenu-arrow',
    RICH:       'ctxmenu-rich',
    DISABLED:   'is-disabled',
    PRESS_LOCK: 'ctxmenu-press-lock',
});

/** ARIA role values */
export const ARIA = Object.freeze({
    MENU:      'menu',
    MENUITEM:  'menuitem',
    SEPARATOR: 'separator',
});

/** Arrow character for sub-menu indicators */
export const ARROW_CHAR = Icons.svg('chevron-right', { size: 12, strokeWidth: 2 });

/** DOM selectors */
export const SEL = Object.freeze({
    FIRST_ENABLED: `.${CLS.ITEM}:not(.${CLS.DISABLED})`,
});

/** Numeric constants */
export const NUMS = Object.freeze({
    VIEWPORT_PADDING:  4,
    SUBMENU_GAP:       2,
    DEFAULT_MENU_SIZE: 200,
    INITIAL_FOCUS_IDX: -1,
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('ContextMenu', {
    MENU        : { class: 'ctxmenu', aliases: ['menu', 'root', 'container'] },
    ITEM        : { class: 'ctxmenu-item', aliases: ['item'] },
    ICON        : { class: 'ctxmenu-icon', aliases: ['icon'] },
    LABEL       : { class: 'ctxmenu-label', aliases: ['label'] },
    SHORTCUT    : { class: 'ctxmenu-shortcut', aliases: ['shortcut'] },
    ARROW       : { class: 'ctxmenu-arrow', aliases: ['arrow'] },
    DIVIDER     : { class: 'ctxmenu-divider' },
    RICH        : { class: 'ctxmenu-rich' },
});

PART.MENU.jit     = 'fixed [min-width:var(--cm-min-width)] [max-width:var(--cm-max-width)] bg-[var(--cm-bg)] [border:1px_solid_var(--cm-border)] rounded-[var(--cm-radius)] [box-shadow:var(--cm-shadow)] [padding:var(--cm-padding-y)_var(--cm-padding-x)] [font-family:inherit] text-[var(--cm-font-size)] fg-[var(--cm-text)] [outline:none]';
PART.ITEM.jit     = 'flex items-center gap-[var(--cm-item-gap)] [padding:var(--cm-item-padding-y)_var(--cm-item-padding-x)] cursor-pointer [outline:none] select-none hover:bg-[var(--cm-bg-hover)] focus-visible:bg-[var(--cm-bg-hover)] {is-disabled}:[opacity:0.4] {is-disabled}:pointer-events-none';
PART.ICON.jit     = 'shrink-0 w-[1.2em] text-center text-[1em]';
PART.LABEL.jit    = TRUNCATE;
PART.SHORTCUT.jit = 'shrink-0 ml-[auto] text-[var(--cm-shortcut-font-size)] fg-[var(--cm-text-muted)] [opacity:.7]';
PART.ARROW.jit    = 'shrink-0 ml-[auto] text-[1.1em] [line-height:1] fg-[var(--cm-text-muted)]';
PART.DIVIDER.jit  = '[height:1px] [margin:var(--cm-divider-margin-y)_var(--cm-divider-margin-x)] bg-[var(--cm-border)]';
PART.RICH.jit     = 'block [padding:.5rem_.75rem] cursor-default hover:[background:transparent]';

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    items:                  [],
    trigger:                'contextmenu',
    className:              '',
    longPressMs:            550,
    longPressMoveThreshold: 8,
    onOpen:                 null,
    onClose:                null,
    onSelect:               null,
});