/**
 * @fileoverview ContextMenu component - modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js - CSS classes, ARIA attrs, selectors, defaults
 *   helpers.js   - pure utility functions (positioning, disabled check)
 *   state.js     - active-menu tracking & global close
 *   view.js      - DOM construction for menus and sub-menus
 *   events.js    - centralised event binding (AbortController cleanup)
 *
 * @module module/ContextMenu
 */

import { default as razyui, Elements } from '../../index.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';

import { DEFAULTS, SEL }          from './constants.js';
import { positionMenu }           from './helpers.js';
import { activeMenus, closeAll }  from './state.js';
import { buildMenu }              from './view.js';
import { bindTrigger, bindMenuItemEvents } from './events.js';

const { isFn, isStr } = razyui;

/**
 * ContextMenu - v2 modular rewrite
 *
 * Right-click (or custom trigger) context menu with nested sub-menus,
 * icons, dividers, rich content slots, and keyboard navigation.
 *
 * Config:
 *   items       - Array of item objects, or function(target, e) -> Array
 *   trigger     - 'contextmenu' | 'click' (default 'contextmenu')
 *   className   - extra CSS class on the menu container
 *
 * Item object:
 *   { label, icon?, action?, items? (submenu), disabled?, content?, divider? }
 *   - label:    string - display text
 *   - icon:     string - HTML or emoji for the icon column
 *   - action:   function(item, target, e) - click handler
 *   - items:    Array - sub-menu (recursive)
 *   - disabled: boolean | function(target) - grey-out
 *   - content:  string | Element - arbitrary rich content (replaces label)
 *   - divider:  true - renders a horizontal rule instead of a clickable item
 *
 * Callbacks:
 *   onOpen(target, e)       - before menu opens; return false to cancel
 *   onClose()               - after menu closes
 *   onSelect(item, target)  - after an item is selected
 *
 * getControl() API:
 *   .open(x, y, target?)   - programmatically open at coordinates
 *   .close()               - close menu
 *   .destroy()             - remove all listeners & DOM
 *   .update(items)         - replace items at runtime
 *
 * @class ContextMenu
 * @param {string|Element|Elements} selector - The DOM selector or element(s) to attach the ContextMenu to.
 * @param {object} config - Configuration options for the ContextMenu.
 */
const ContextMenu = class {

    #targets        = null;   // Elements collection
    #config         = {};
    #items          = [];
    #destroyed      = false;
    #eventAC   = null;

    constructor(selector, config = {}) {
        const targets = isStr(selector)
            ? razyui(selector)
            : (selector instanceof Elements ? selector : new Elements(selector));

        if (!targets.length) {
            console.warn('ContextMenu: element not found \u2192', selector);
            return;
        }

        this.#targets = targets;
        this.#config  = { ...DEFAULTS, ...config };
        this.#items   = this.#config.items;

        this.#eventAC = bindTrigger(
            targets,
            this.#config,
            (target, e, preventDefault) => this.#openMenu(target, e, preventDefault),
            () => !this.#destroyed,
        );
    }

    #openMenu(target, e, preventDefault) {
        if (this.#destroyed) return;
        if (preventDefault && e?.preventDefault) {
            e.preventDefault();
            e.stopPropagation();
        }

        const cfg = this.#config;

        // onOpen callback - may cancel
        if (isFn(cfg.onOpen) && cfg.onOpen(target, e) === false) return;

        closeAll();

        // Resolve items (may be dynamic)
        let items = this.#items;
        if (isFn(items)) items = items(target, e);
        if (!Array.isArray(items) || !items.length) return;

        const menu = buildMenu(items, target, cfg, 0, bindMenuItemEvents);
        razyui(document.body).append(menu);
        zIndexRegistry.acquire(menu);
        activeMenus.add(menu);
        bindMenuItemEvents(menu);

        // Position at cursor
        const x = e?.clientX ?? e?.pageX ?? 0;
        const y = e?.clientY ?? e?.pageY ?? 0;
        positionMenu(menu, x, y);

        // Focus first item after frame
        requestAnimationFrame(() => {
            positionMenu(menu, x, y); // re-adjust after render
            const first = razyui(menu).find(SEL.FIRST_ENABLED)[0];
            if (first) first.focus();
        });
    }

    getControl() {
        const self = this;
        return {
            open: (x, y, target) => {
                closeAll();
                let items = self.#items;
                if (isFn(items)) items = items(target);
                if (!Array.isArray(items) || !items.length) return;

                const menu = buildMenu(items, target || document.body, self.#config, 0, bindMenuItemEvents);
                razyui(document.body).append(menu);
                activeMenus.add(menu);
                bindMenuItemEvents(menu);
                positionMenu(menu, x, y);

                requestAnimationFrame(() => {
                    positionMenu(menu, x, y);
                    const first = razyui(menu).find(SEL.FIRST_ENABLED)[0];
                    if (first) first.focus();
                });
            },
            close:   () => closeAll(),
            destroy: () => self.#destroy(),
            update:  (items) => { self.#items = items; },
            get element() { return self.#targets?.[0] ?? null; },
            get destroyed() { return self.#destroyed; },
        };
    }

    #destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        closeAll();
    }
};

export default ContextMenu;
